// Parse positions with error handling and defaults
let positions = {};
try {
  const binaryData = $('Load Positions').first().binary?.data?.data;
  if (binaryData) {
    const parsed = JSON.parse(Buffer.from(binaryData, 'base64').toString('utf-8'));
    positions = parsed.positions || {};
  }
} catch (e) {
  console.log('Positions file not found or invalid, using empty defaults');
  positions = {};
}

const watchlist = {
  stocks: ['NVDA', 'MSFT', 'GOOGL', 'AAPL', 'VOO', 'META', 'AMZN'],
  crypto: ['ethereum', 'solana']
};

return [{
  json: {
    positions,
    watchlist,
    timestamp: new Date().toISOString(),
    source: 'Trading Signals Monitor v2.0'
  }
}];

const input = $input.first().json;
const signals = input.signals || [];
const timestamp = input.timestamp;
const optimizedParams = input.optimizedParams || {};

// Categorize signals by priority with optimized thresholds
const critical = signals.filter(s => 
  s.urgency === 'critical' || (s.confidence >= 85 && s.action !== 'hold')
);

const high = signals.filter(s => 
  (s.confidence >= 75 && s.confidence < 85 && s.action !== 'hold') ||
  (s.urgency === 'high' && s.confidence >= 65)
);

const medium = signals.filter(s => 
  s.urgency === 'medium' || 
  (s.confidence >= 60 && s.confidence < 75 && s.action !== 'hold')
);

const low = signals.filter(s => s.confidence < 60 || s.action === 'hold');

// Discord: Critical and High (confidence >= 75)
const discordSignals = [...critical, ...high.filter(s => s.confidence >= 75)];

// Build Discord message
let discordMessage = '';
if (discordSignals.length > 0) {
  const now = new Date();
  const timeStr = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });

  if (critical.length > 0) {
    discordMessage = '**🚨 CRITICAL ALERTS**\n\n';
    critical.forEach(s => {
      const emoji = s.action === 'buy' ? '🟢' : s.action === 'sell' ? '🔴' : '⚪';
      discordMessage += `${emoji} **${s.symbol}**: ${s.action.toUpperCase()} (${s.confidence}/100)\n`;
      discordMessage += `> ${s.reason}\n`;
      if (s.tech_reasons?.length) discordMessage += `> Tech: ${s.tech_reasons.join(', ')}\n`;
      if (s.key_levels) {
        discordMessage += `> Levels: Entry $${s.key_levels.entry} | Stop $${s.key_levels.stop} | Target $${s.key_levels.target}\n`;
      }
    });
    discordMessage += '\n';
  }

  if (high.filter(s => s.confidence >= 75).length > 0) {
    discordMessage += '**📊 High Priority Signals**\n';
    high.filter(s => s.confidence >= 75).forEach(s => {
      const emoji = s.action === 'buy' ? '🟢' : s.action === 'sell' ? '🔴' : '⚪';
      discordMessage += `${emoji} ${s.symbol}: ${s.action.toUpperCase()} (${s.confidence}/100)\n`;
      discordMessage += `   ${s.reason}\n`;
    });
  }

  discordMessage += `\n⏰ ${timeStr} PT`;
}

// Build Obsidian content (all signals)
const obsidianLines = [];
const now = new Date();
obsidianLines.push(`# Trading Signals - ${now.toISOString().split('T')[0]}`);
obsidianLines.push(`\n**Time:** ${now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })} PT`);
obsidianLines.push(`\n**Optimized Parameters Active:** ✅`);
obsidianLines.push(`- RSI Oversold: ${optimizedParams.thresholds?.rsi_oversold || 30}`);
obsidianLines.push(`- RSI Overbought: ${optimizedParams.thresholds?.rsi_overbought || 70}`);
obsidianLines.push(`- Volume Spike: ${optimizedParams.thresholds?.volume_spike_multiplier || 1.5}x\n`);
obsidianLines.push(`## Market Overview\n${input.market_overview || 'N/A'}\n`);

if (signals.length > 0) {
  obsidianLines.push('## Signals\n');

  if (critical.length > 0) {
    obsidianLines.push('### 🚨 Critical\n');
    critical.forEach(s => {
      obsidianLines.push(`#### ${s.symbol} - ${s.action.toUpperCase()}`);
      obsidianLines.push(`- **Confidence:** ${s.confidence}/100`);
      obsidianLines.push(`- **Urgency:** ${s.urgency || 'critical'}`);
      obsidianLines.push(`- **Price:** $${s.price || 'N/A'}`);
      obsidianLines.push(`- **Reason:** ${s.reason}`);
      if (s.tech_reasons?.length) obsidianLines.push(`- **Technical:** ${s.tech_reasons.join(', ')}`);
      if (s.key_levels) obsidianLines.push(`- **Levels:** Entry $${s.key_levels.entry}, Stop $${s.key_levels.stop}, Target $${s.key_levels.target}`);
      obsidianLines.push('');
    });
  }

  if (high.length > 0) {
    obsidianLines.push('### 📊 High Priority\n');
    high.forEach(s => {
      obsidianLines.push(`#### ${s.symbol} - ${s.action.toUpperCase()}`);
      obsidianLines.push(`- **Confidence:** ${s.confidence}/100`);
      obsidianLines.push(`- **Price:** $${s.price || 'N/A'}`);
      obsidianLines.push(`- **Reason:** ${s.reason}`);
      if (s.tech_reasons?.length) obsidianLines.push(`- **Technical:** ${s.tech_reasons.join(', ')}`);
      obsidianLines.push('');
    });
  }

  if (medium.length > 0) {
    obsidianLines.push('### ⚪ Medium Priority\n');
    medium.forEach(s => {
      obsidianLines.push(`- ${s.symbol}: ${s.action.toUpperCase()} (${s.confidence}/100) - ${s.reason}`);
    });
    obsidianLines.push('');
  }
}

obsidianLines.push('## Recommendations');
obsidianLines.push(input.recommendations || 'N/A');
obsidianLines.push('\n## Risk Assessment');
obsidianLines.push(input.risk_assessment || 'N/A');

if (optimizedParams.performance_metrics) {
  obsidianLines.push('\n## Backtest Performance (Walk-Forward Validated)');
  obsidianLines.push(`- **Avg Sharpe Ratio:** ${optimizedParams.performance_metrics.avg_sharpe_ratio}`);
  obsidianLines.push(`- **Avg Total Return:** ${optimizedParams.performance_metrics.avg_total_return}%`);
  obsidianLines.push(`- **Optimization Date:** ${optimizedParams.performance_metrics.optimization_date}`);
}

// Truncate to Discord's 2000 char limit
if (discordMessage.length > 1950) {
  discordMessage = discordMessage.substring(0, 1940) + '\n…(truncated)';
}

return [{
  json: {
    sendDiscord: discordMessage.length > 0,
    discordMessage,
    obsidianContent: obsidianLines.join('\n'),
    signals,
    criticalCount: critical.length,
    highCount: high.length,
    mediumCount: medium.length,
    lowCount: low.length,
    timestamp,
    optimizedParams
  }
}];

// Prepare binary data for file writing
const input = $('Route Signals').first().json;
const obsidianContent = input.obsidianContent;

const binaryData = Buffer.from(obsidianContent).toString('base64');
const filename = new Date().toISOString().split('T')[0] + '.md';

return [{
  json: {
    ...input,
    filepath: '/home/ubuntu/.n8n-files/Trading/signals/' + filename,
    filename
  },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'text/markdown',
      fileName: filename,
      fileExtension: 'md'
    }
  }
}];

const input = $('Route Signals').first().json;
const obsidianContent = input.obsidianContent;
const filename = new Date().toISOString().split('T')[0] + '.md';

return [{
  json: {
    filename,
    filepath: '/home/ubuntu/.n8n-files/Trading/signals/' + filename,
    content: obsidianContent,
    append: true
  }
}];

const input = $('Route Signals').first().json;
const signals = input.signals || [];
if (signals.length === 0) return [{ json: { skip: true } }];

const newEntries = signals.map(s => ({
  symbol: s.symbol,
  action: s.action,
  confidence: s.confidence,
  urgency: s.urgency || 'medium',
  reason: s.reason,
  tech_reasons: s.tech_reasons || [],
  price: s.price,
  timestamp: input.timestamp,
  outcome: 'pending',
  key_levels: s.key_levels || null
}));

return [{
  json: {
    signals: newEntries,
    filepath: '/home/ubuntu/.n8n-files/Trading/performance/metrics.json'
  }
}];

const newSignals = $('Log Signals').first().json.signals;
let metrics = { signals: [], accuracy: { overall: 0, by_type: {} }, last_updated: null };

try {
  const binaryData = $input.first().binary?.data?.data;
  if (binaryData) {
    metrics = JSON.parse(Buffer.from(binaryData, 'base64').toString('utf-8'));
  }
} catch (e) {}

metrics.signals = [...(metrics.signals || []), ...newSignals];

if (metrics.signals.length > 500) {
  metrics.signals = metrics.signals.slice(-500);
}

metrics.last_updated = new Date().toISOString();

const metricsJson = JSON.stringify(metrics, null, 2);
const binaryContent = Buffer.from(metricsJson).toString('base64');

return [{
  json: {
    filepath: '/home/ubuntu/.n8n-files/Trading/performance/metrics.json'
  },
  binary: {
    data: {
      data: binaryContent,
      mimeType: 'application/json',
      fileName: 'metrics.json'
    }
  }
}];

// Save latest signals as JSON for Python integration
const input = $('Route Signals').first().json;
const signals = input.signals || [];

const jsonContent = JSON.stringify({
  timestamp: input.timestamp,
  signals: signals,
  market_overview: input.market_overview,
  recommendations: input.recommendations,
  risk_assessment: input.risk_assessment,
  optimized_params: input.optimizedParams
}, null, 2);

return [{
  json: {
    filepath: '/home/ubuntu/.n8n-files/Trading/signals/latest_signals.json'
  },
  binary: {
    data: {
      data: Buffer.from(jsonContent).toString('base64'),
      mimeType: 'application/json',
      fileName: 'latest_signals.json'
    }
  }
}];
